// Pull the Usage Summary output from the Alephant node
const d = $('Fetch Alephant Usage Summary').first().json.data;

// Cost: total_cost_cents is in CENTS - convert to dollars
const costUSD = (d.total_cost_cents / 100).toFixed(2);

// Round the week-over-week percentages (they come back as long floats)
const costPct = Math.round(d.vs_previous_period.cost_pct);
const reqPct  = Math.round(d.vs_previous_period.requests_pct);

// Helper: turn a +/- number into a readable trend phrase
const trend = (pct) => {
  if (pct > 0) return `up ${pct}% vs previous period`;
  if (pct < 0) return `down ${Math.abs(pct)}% vs previous period`;
  return `no change vs previous period`;
};

const totalTokens = d.total_tokens.input + d.total_tokens.output;

// Build the email body (plain text)
const body =
`AI Agent Cost Report - Alephant AI Gateway

Period: ${d.period.from} to ${d.period.to}

Total cost:     $${costUSD} (${trend(costPct)})
Total requests: ${d.total_requests} (${trend(reqPct)})
Total tokens:   ${totalTokens} (input ${d.total_tokens.input} / output ${d.total_tokens.output})

Data source: ${d.data_source}${d.degraded ? ' (WARNING: data may be degraded)' : ''}

Sent automatically by your Alephant AI Gateway workflow.`;

// Pass the body + recipient on to the Gmail node
return [{
  json: {
    email_subject: `AI Agent Cost Report (${d.period.from} to ${d.period.to})`,
    email_body: body,
    recipient_email: $('Set Email Recipient').first().json.recipient_email
  }
}];
